  const [loopNum, setLoopNum] = useState(0);
  const [typingSpeed, setTypingSpeed] = useState(150);

  const toRotate = ["Tech Professional", "Product Designer", "Product Manager", "Software Engineer", "Data Analyst", "Technical Writer"];
  const period = 2000;

