              <Button className="mt-10" onClick={onClose}>Close</Button>
            </div>
          ) : (
            <form onSubmit={handleSubmit} className="space-y-8">
              <section>
                <h4 className="text-[#135291] font-bold text-sm mb-5 pb-2 border-b border-gray-100">1. Basic Information</h4>
