      document.body.style.overflow = 'hidden';
      setSubmitted(false);
    } else {
      document.body.style.overflow = 'unset';
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleToggle = (list: string[], item: string, key: keyof typeof formData) => {
    const currentList = list as string[];
    const newList = currentList.includes(item) 
      ? currentList.filter(i => i !== item) 
      : [...currentList, item];
    setFormData({ ...formData, [key]: newList });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (isSubmitting) return;

    setIsSubmitting(true);

    try {
      // We use 'no-cors' mode for Google Apps Script to avoid preflight issues
      // although it means we can't read the JSON response. 
      // Most developers use this "fire and forget" method for simple GAS forms.
      await fetch(SCRIPT_URL, {
        method: 'POST',
        mode: 'no-cors',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...formData,
          timestamp: new Date().toLocaleString(),
          formType: mode === 'facilitator' ? 'Facilitator' : 'Partner',
          supporterType: formData.supporterType.join(', '),
          interests: formData.interests.join(', '),
          intentions: formData.intentions.join(', '),
          expectation: formData.expectation === 'Other' ? formData.otherExpectations : formData.expectation
        }),
