const FACILITATOR_SCRIPT_URL = "YOUR_FACILITATOR_SHEET_URL_HERE";

const orgSizes = ['Individual', 'Startup', 'SME', 'Enterprise', 'NGO'];
const supporterTypes = [
  'Sponsor (Financial support)',
