                    {!isFacilitatorMode && (
                      <div className="mt-4">
                        <label className={labelClasses}>Organization Size (Optional)</label>
                        <div className="relative">
                          <select className={selectClasses} value={formData.orgSize} onChange={e => setFormData({...formData, orgSize: e.target.value})}>
