3. In the first row (A1 to L1), type these exact headers:
   `timestamp`, `fullName`, `orgName`, `role`, `email`, `phone`, `location`, `website`, `orgSize`, `supporterType`, `motivation`, `expectation`

### Step 2: Add the Google Apps Script
1. In your Google Sheet, go to **Extensions** > **Apps Script**.
2. Delete any code there and paste this:

```javascript
function doPost(e) {
  try {
    var sheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('Partners');
    var data = JSON.parse(e.postData.contents);

    // The keys here MUST match what the React app sends
    var row = [
      data.timestamp,
      data.fullName,
      data.orgName,
      data.role,
      data.email,
      data.phone,
      data.location,
      data.website,
      data.orgSize,
      data.supporterType,
      data.motivation,
      data.expectation
    ];

    sheet.appendRow(row);

    return ContentService.createTextOutput(JSON.stringify({ 'result': 'success' }))
      .setMimeType(ContentService.MimeType.JSON);
