In a tech-education platform like yours, **Source** is a tracking label used to identify exactly where a user was on your website when they filled out the form. For example, if someone joins through the "Community Hub" vs the "Footer Link", the source tells you which marketing path is working best. It helps you stay organized by showing you the "origin" of every row in your database.

### The Google Apps Script (Complete & Optimized)

This is the single script you need. It handles all forms, routes data to the correct tabs, and even auto-creates headers if the sheet is empty.

```javascript
function doPost(e) {
  try {
    var data = JSON.parse(e.postData.contents);
    var ss = SpreadsheetApp.getActiveSpreadsheet();

    // 1. Determine which tab to use
    var sheetName = data.sheetName || "General_Submissions";
    var sheet = ss.getSheetByName(sheetName);

    // 2. Create the tab if it doesn't exist
    if (!sheet) {
      sheet = ss.insertSheet(sheetName);
    }

    var row = [];

    // 3. Map data based on the specific sheet name requirements
    if (sheetName === "Community") {
      row = [
        data.timestamp,
        data.source,
        data.firstName,
        data.lastName,
        data.email,
        data.whatsapp,
        data.track,
        data.country,
        data.experience,
        data.dob // This is the Birthday field
      ];
    } 
    else if (sheetName === "Volunteer") {
      row = [
        data.timestamp,
        data.source,
        data.firstName,
        data.lastName,
        data.email,
        data.department,
        data.linkedin,
        data.reason
      ];
    } 
    else if (sheetName === "Facilitators") {
      row = [
        data.timestamp,
        data.source,
        data.fullName,
        data.orgName,
        data.email,
        data.phone,
        data.location,
        data.trackInterestedIn,
        data.motivation
      ];
    } 
    else if (sheetName === "Partners") {
      row = [
        data.timestamp,
        data.source,
        data.fullName,
        data.orgName,
        data.email,
        data.phone,
        data.location,
        data.supporterType, // This contains the selected checkbox values
        data.motivation
      ];
    } else {
      // Fallback for any other unexpected data
      row = [data.timestamp, data.source, "Other Data", JSON.stringify(data)];
    }

    sheet.appendRow(row);

    return ContentService.createTextOutput("Success")
      .setMimeType(ContentService.MimeType.TEXT);

  } catch (error) {
    return ContentService.createTextOutput("Error: " + error.toString())
      .setMimeType(ContentService.MimeType.TEXT);
  }
}
```

